import React, { useState } from "react";
import Home from "./pages/Home";
import Grade2 from "./pages/Grade2";
import Grade3 from "./pages/Grade3";
import Grade4 from "./pages/Grade4";

function App() {
  const [page, setPage] = useState("home");

  if (page === "grade2") return <Grade2 setPage={setPage} />;
  if (page === "grade3") return <Grade3 setPage={setPage} />;
  if (page === "grade4") return <Grade4 setPage={setPage} />;

  return <Home setPage={setPage} />;
}

export default App;
